/**
 * Check if a notification should be delivered to a user on a given channel.
 *
 * Returns true if:
 * - No preferences exist for the user (default: allow all)
 * - The channel is enabled AND the notification type is in subscribed categories
 *
 * Currently only 'email' channel is supported.
 */
shouldSendNotification(
  userId: string,
  channel: NotificationChannel,
  notificationType: NotificationType,
): boolean {
  const preferences = this.preferencesRepository.findByUserId(userId);

  // No preferences stored — default to sending
  if (!preferences) {
    return true;
  }

  if (channel === 'email') {
    if (!preferences.email.enabled) {
      this.logger.info(`Email notifications disabled for user ${userId}`);
      return false;
    }
    if (preferences.email.frequency === 'none') {
      this.logger.info(`Email frequency set to none for user ${userId}`);
      return false;
    }
    if (!preferences.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(
        `User ${userId} not subscribed to ${notificationType} emails`,
      );
      return false;
    }
    return true;
  }

  // For unsupported channels, default to sending
  return true;
}

