import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with all channel defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email).toEqual(DEFAULT_EMAIL_PREFERENCES);
      expect(prefs.sms).toEqual(DEFAULT_SMS_PREFERENCES);
      expect(prefs.webhook).toEqual(DEFAULT_WEBHOOK_PREFERENCES);
    });

    it('should allow overriding email preferences', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('immediate'); // default preserved
      expect(prefs.sms).toEqual(DEFAULT_SMS_PREFERENCES);
    });

    it('should allow overriding SMS preferences', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        sms: { enabled: false },
      });

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toEqual(DEFAULT_SMS_PREFERENCES.subscribedCategories);
      expect(prefs.email).toEqual(DEFAULT_EMAIL_PREFERENCES);
    });

    it('should allow overriding webhook preferences', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: false, url: 'https://example.com/hook' },
      });

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.url).toBe('https://example.com/hook');
      expect(prefs.webhook.subscribedCategories).toEqual(DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories);
    });

    it('should allow custom subscribedCategories per channel', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order_confirmation'] },
        sms: { subscribedCategories: ['order_status_update'] },
        webhook: { subscribedCategories: ['welcome', 'account_updated'] },
      });

      expect(prefs.email.subscribedCategories).toEqual(['order_confirmation']);
      expect(prefs.sms.subscribedCategories).toEqual(['order_status_update']);
      expect(prefs.webhook.subscribedCategories).toEqual(['welcome', 'account_updated']);
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });
  });

  describe('updatePreferences', () => {
    it('should update SMS preferences only', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        sms: { enabled: false },
      });

      expect(updated.sms.enabled).toBe(false);
      expect(updated.email).toEqual(DEFAULT_EMAIL_PREFERENCES);
      expect(updated.webhook).toEqual(DEFAULT_WEBHOOK_PREFERENCES);
    });

    it('should update webhook preferences only', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: false },
      });

      expect(updated.webhook.enabled).toBe(false);
      expect(updated.email).toEqual(DEFAULT_EMAIL_PREFERENCES);
      expect(updated.sms).toEqual(DEFAULT_SMS_PREFERENCES);
    });

    it('should update multiple channels at once', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.sms.enabled).toBe(false);
      expect(updated.webhook.enabled).toBe(false);
    });

    it('should update subscribedCategories for SMS', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        sms: { subscribedCategories: ['order_confirmation'] },
      });

      expect(updated.sms.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should throw if preferences do not exist', () => {
      expect(() =>
        service.updatePreferences('user-1', { sms: { enabled: false } }),
      ).toThrow('Preferences not found for user: user-1');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should return existing preferences with all channels', () => {
      const created = service.createPreferences({
        userId: 'user-1',
        sms: { enabled: false },
      });
      const retrieved = service.getOrCreatePreferences('user-1');

      expect(retrieved.id).toBe(created.id);
      expect(retrieved.sms.enabled).toBe(false);
    });

    it('should create defaults with all channels for new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.email).toEqual(DEFAULT_EMAIL_PREFERENCES);
      expect(prefs.sms).toEqual(DEFAULT_SMS_PREFERENCES);
      expect(prefs.webhook).toEqual(DEFAULT_WEBHOOK_PREFERENCES);
    });
  });

  describe('shouldSendNotification', () => {
    it('should return true when no preferences exist', () => {
      expect(service.shouldSendNotification('user-1', 'sms', 'order_confirmation')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'webhook', 'order_confirmation')).toBe(true);
    });

    // --- Email channel ---
    it('should respect email enabled toggle', () => {
      service.createPreferences({ userId: 'user-1', email: { enabled: false } });
      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(false);
    });

    it('should respect email frequency none', () => {
      service.createPreferences({ userId: 'user-1', email: { frequency: 'none' } });
      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(false);
    });

    it('should respect email subscribed categories', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['welcome'] },
      });
      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'email', 'welcome')).toBe(true);
    });

    // --- SMS channel ---
    it('should respect SMS enabled toggle', () => {
      service.createPreferences({ userId: 'user-1', sms: { enabled: false } });
      expect(service.shouldSendNotification('user-1', 'sms', 'order_confirmation')).toBe(false);
    });

    it('should allow SMS when enabled and category subscribed', () => {
      service.createPreferences({ userId: 'user-1' }); // defaults: all enabled
      expect(service.shouldSendNotification('user-1', 'sms', 'order_confirmation')).toBe(true);
    });

    it('should respect SMS subscribed categories', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { subscribedCategories: ['order_status_update'] },
      });
      expect(service.shouldSendNotification('user-1', 'sms', 'order_confirmation')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'sms', 'order_status_update')).toBe(true);
    });

    // --- Webhook channel ---
    it('should respect webhook enabled toggle', () => {
      service.createPreferences({ userId: 'user-1', webhook: { enabled: false } });
      expect(service.shouldSendNotification('user-1', 'webhook', 'order_confirmation')).toBe(false);
    });

    it('should allow webhook when enabled and category subscribed', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSendNotification('user-1', 'webhook', 'welcome')).toBe(true);
    });

    it('should respect webhook subscribed categories', () => {
      service.createPreferences({
        userId: 'user-1',
        webhook: { subscribedCategories: ['account_updated'] },
      });
      expect(service.shouldSendNotification('user-1', 'webhook', 'order_confirmation')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'webhook', 'account_updated')).toBe(true);
    });

    // --- Cross-channel independence ---
    it('should allow disabling one channel without affecting others', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
        sms: { enabled: true },
        webhook: { enabled: true },
      });
      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'sms', 'order_confirmation')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'webhook', 'order_confirmation')).toBe(true);
    });

    it('should allow different category subscriptions per channel', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order_confirmation'] },
        sms: { subscribedCategories: ['order_status_update'] },
        webhook: { subscribedCategories: ['welcome'] },
      });

      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'email', 'order_status_update')).toBe(false);

      expect(service.shouldSendNotification('user-1', 'sms', 'order_status_update')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'sms', 'order_confirmation')).toBe(false);

      expect(service.shouldSendNotification('user-1', 'webhook', 'welcome')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'webhook', 'order_confirmation')).toBe(false);
    });

    // --- Unknown channels ---
    it('should default to sending for unknown channels', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSendNotification('user-1', 'in_app', 'order_confirmation')).toBe(true);
    });
  });

  describe('deletePreferences', () => {
    it('should delete preferences', () => {
      service.createPreferences({ userId: 'user-1' });
